package membership

import (
	"math/bits"
	"sync"
	"time"
)

// ScaledConfig derives SWIM timing and fanout values from a cluster size.
//
// Scaling uses ceil(log2(clusterSize)) as its deterministic scale factor. A
// cluster size of zero or one uses Base unchanged, and each subsequent log2
// boundary adds the configured step values. The protocol period maps to
// SWIMConfig.ProbeInterval.
type ScaledConfig struct {
	// Base is the SWIM configuration used for a zero or single-node cluster.
	Base SWIMConfig

	// ProtocolPeriodStep is added to Base.ProbeInterval per log2 scale step.
	ProtocolPeriodStep time.Duration
	// ProbeTimeoutStep is added to Base.ProbeTimeout per log2 scale step.
	ProbeTimeoutStep time.Duration
	// SuspicionTimeoutStep is added to Base.SuspicionTimeout per log2 scale step.
	SuspicionTimeoutStep time.Duration

	// IndirectChecksStep is added to Base.IndirectChecks per log2 scale step.
	IndirectChecksStep int
	// MaxIndirectChecks caps the scaled indirect check fanout. A value <= 0 means no cap.
	MaxIndirectChecks int
}

// DefaultScaling returns log2-based scaling defaults for SWIM.
func DefaultScaling() ScaledConfig {
	return ScaledConfig{
		Base:                 DefaultSWIMConfig(),
		ProtocolPeriodStep:   250 * time.Millisecond,
		ProbeTimeoutStep:     100 * time.Millisecond,
		SuspicionTimeoutStep: time.Second,
		IndirectChecksStep:   1,
		MaxIndirectChecks:    32,
	}
}

// Scale returns ceil(log2(clusterSize)), with zero and one mapped to zero.
func (c ScaledConfig) Scale(clusterSize int) int {
	return log2Scale(clusterSize)
}

// Log2Scale returns ceil(log2(clusterSize)), with zero and one mapped to zero.
func (c ScaledConfig) Log2Scale(clusterSize int) int {
	return c.Scale(clusterSize)
}

// ConfigFor returns a SWIMConfig scaled for clusterSize.
func (c ScaledConfig) ConfigFor(clusterSize int) SWIMConfig {
	return c.SWIMConfig(clusterSize)
}

// SWIMConfig returns a SWIMConfig scaled for clusterSize.
func (c ScaledConfig) SWIMConfig(clusterSize int) SWIMConfig {
	n := c.normalized()
	scale := n.Scale(clusterSize)

	return SWIMConfig{
		ProbeInterval:    scaleDuration(n.Base.ProbeInterval, n.ProtocolPeriodStep, scale),
		ProbeTimeout:     scaleDuration(n.Base.ProbeTimeout, n.ProbeTimeoutStep, scale),
		IndirectChecks:   scaleInt(n.Base.IndirectChecks, n.IndirectChecksStep, n.MaxIndirectChecks, scale),
		SuspicionTimeout: scaleDuration(n.Base.SuspicionTimeout, n.SuspicionTimeoutStep, scale),
	}
}

// ProtocolPeriod returns the scaled SWIM protocol period for clusterSize.
func (c ScaledConfig) ProtocolPeriod(clusterSize int) time.Duration {
	return c.SWIMConfig(clusterSize).ProbeInterval
}

// ProbeTimeout returns the scaled direct probe timeout for clusterSize.
func (c ScaledConfig) ProbeTimeout(clusterSize int) time.Duration {
	return c.SWIMConfig(clusterSize).ProbeTimeout
}

// IndirectChecks returns the scaled indirect probe fanout for clusterSize.
func (c ScaledConfig) IndirectChecks(clusterSize int) int {
	return c.SWIMConfig(clusterSize).IndirectChecks
}

// SuspicionTimeout returns the scaled suspicion timeout for clusterSize.
func (c ScaledConfig) SuspicionTimeout(clusterSize int) time.Duration {
	return c.SWIMConfig(clusterSize).SuspicionTimeout
}

// ClusterSizeEstimator tracks observed node IDs and reports the current estimate.
//
// The zero value is ready to use and retains observations indefinitely. Set
// Window to a positive duration to expire observations older than that window.
type ClusterSizeEstimator struct {
	// Window controls how long observations remain current. A value <= 0 retains
	// observations indefinitely.
	Window time.Duration

	mu       sync.Mutex
	observed map[string]time.Time
}

// NewClusterSizeEstimator returns an estimator with the given observation window.
func NewClusterSizeEstimator(window time.Duration) *ClusterSizeEstimator {
	return &ClusterSizeEstimator{Window: window}
}

// Observe records a node as seen at the current time.
func (e *ClusterSizeEstimator) Observe(nodeID string) {
	e.ObserveAt(nodeID, time.Now())
}

// ObserveAt records a node as seen at observedAt.
func (e *ClusterSizeEstimator) ObserveAt(nodeID string, observedAt time.Time) {
	if nodeID == "" {
		return
	}

	e.mu.Lock()
	defer e.mu.Unlock()
	e.ensureObserved()
	e.observed[nodeID] = observedAt
}

// ObserveNodes records multiple nodes as seen at the current time.
func (e *ClusterSizeEstimator) ObserveNodes(nodeIDs ...string) {
	e.ObserveNodesAt(time.Now(), nodeIDs...)
}

// ObserveNodesAt records multiple nodes as seen at observedAt.
func (e *ClusterSizeEstimator) ObserveNodesAt(observedAt time.Time, nodeIDs ...string) {
	e.mu.Lock()
	defer e.mu.Unlock()
	e.ensureObserved()
	for _, nodeID := range nodeIDs {
		if nodeID != "" {
			e.observed[nodeID] = observedAt
		}
	}
}

// Estimate returns the current cluster size estimate.
func (e *ClusterSizeEstimator) Estimate() int {
	return e.EstimateAt(time.Now())
}

// EstimateAt returns the cluster size estimate at now.
func (e *ClusterSizeEstimator) EstimateAt(now time.Time) int {
	e.mu.Lock()
	defer e.mu.Unlock()
	if e.observed == nil {
		return 0
	}
	e.pruneLocked(now)
	return len(e.observed)
}

// Forget removes a node from the estimate.
func (e *ClusterSizeEstimator) Forget(nodeID string) bool {
	e.mu.Lock()
	defer e.mu.Unlock()
	if e.observed == nil {
		return false
	}
	if _, ok := e.observed[nodeID]; !ok {
		return false
	}
	delete(e.observed, nodeID)
	return true
}

// Reset clears all observations.
func (e *ClusterSizeEstimator) Reset() {
	e.mu.Lock()
	defer e.mu.Unlock()
	e.observed = nil
}

func (c ScaledConfig) normalized() ScaledConfig {
	def := DefaultScaling()
	base := c.Base
	if base.ProbeInterval <= 0 && base.ProbeTimeout <= 0 && base.IndirectChecks == 0 && base.SuspicionTimeout <= 0 {
		base = def.Base
	} else {
		if base.ProbeInterval <= 0 {
			base.ProbeInterval = def.Base.ProbeInterval
		}
		if base.ProbeTimeout <= 0 {
			base.ProbeTimeout = def.Base.ProbeTimeout
		}
		if base.IndirectChecks < 0 {
			base.IndirectChecks = 0
		}
		if base.SuspicionTimeout <= 0 {
			base.SuspicionTimeout = def.Base.SuspicionTimeout
		}
	}

	if c.ProtocolPeriodStep < 0 {
		c.ProtocolPeriodStep = 0
	}
	if c.ProbeTimeoutStep < 0 {
		c.ProbeTimeoutStep = 0
	}
	if c.SuspicionTimeoutStep < 0 {
		c.SuspicionTimeoutStep = 0
	}
	if c.IndirectChecksStep < 0 {
		c.IndirectChecksStep = 0
	}

	c.Base = base
	return c
}

func log2Scale(clusterSize int) int {
	if clusterSize <= 1 {
		return 0
	}
	return bits.Len(uint(clusterSize - 1))
}

func scaleDuration(base, step time.Duration, scale int) time.Duration {
	if base < 0 {
		base = 0
	}
	if step <= 0 || scale <= 0 {
		return base
	}

	maxDuration := time.Duration(1<<63 - 1)
	scaledBy := time.Duration(scale)
	if step > (maxDuration-base)/scaledBy {
		return maxDuration
	}
	return base + step*scaledBy
}

func scaleInt(base, step, max, scale int) int {
	if base < 0 {
		base = 0
	}
	if step <= 0 || scale <= 0 {
		return capInt(base, max)
	}
	if step > (int(^uint(0)>>1)-base)/scale {
		return capInt(int(^uint(0)>>1), max)
	}
	return capInt(base+step*scale, max)
}

func capInt(value, max int) int {
	if max > 0 && value > max {
		return max
	}
	return value
}

func (e *ClusterSizeEstimator) ensureObserved() {
	if e.observed == nil {
		e.observed = make(map[string]time.Time)
	}
}

func (e *ClusterSizeEstimator) pruneLocked(now time.Time) {
	if e.Window <= 0 {
		return
	}
	cutoff := now.Add(-e.Window)
	for nodeID, observedAt := range e.observed {
		if observedAt.Before(cutoff) {
			delete(e.observed, nodeID)
		}
	}
}

