	tests := []struct {
		size  int
		scale int
	}{
		{0, 0},
		{1, 0},
		{2, 1},
		{3, 2},
		{4, 2},
		{7, 3},
		{8, 3},
		{9, 4},
		{16, 4},
		{1024, 10},
		{1 << 20, 20},
	}

	for _, tc := range tests {
		if got := scaling.Scale(tc.size); got != tc.scale {
			t.Fatalf("scale(%d) = %d, want %d", tc.size, got, tc.scale)
		}

		wantPeriod := base.ProbeInterval + time.Duration(tc.scale)*scaling.ProtocolPeriodStep
		if got := scaling.ProtocolPeriod(tc.size); got != wantPeriod {
			t.Fatalf("period(%d) = %s, want %s", tc.size, got, wantPeriod)
		}

		wantTimeout := base.ProbeTimeout + time.Duration(tc.scale)*scaling.ProbeTimeoutStep
		if got := scaling.ProbeTimeout(tc.size); got != wantTimeout {
			t.Fatalf("probe timeout(%d) = %s, want %s", tc.size, got, wantTimeout)
		}

		wantSuspicion := base.SuspicionTimeout + time.Duration(tc.scale)*scaling.SuspicionTimeoutStep
		if got := scaling.SuspicionTimeout(tc.size); got != wantSuspicion {
			t.Fatalf("suspicion timeout(%d) = %s, want %s", tc.size, got, wantSuspicion)
		}
	}
}

func TestScaledConfigLargeCounts(t *testing.T) {
	scaling := DefaultScaling()
	size := 1 << 30

	if got := scaling.Scale(size); got != 30 {
		t.Fatalf("scale(%d) = %d, want 30", size, got)
	}

	cfg := scaling.SWIMConfig(size)
	if cfg.ProbeInterval != 8500*time.Millisecond {
		t.Fatalf("large cluster period = %s, want 8.5s", cfg.ProbeInterval)
	}
	if cfg.IndirectChecks != scaling.MaxIndirectChecks {
		t.Fatalf("large cluster indirect checks = %d, want cap %d", cfg.IndirectChecks, scaling.MaxIndirectChecks)
	}
}

func TestClusterSizeEstimatorObservations(t *testing.T) {
	var estimator ClusterSizeEstimator

	if got := estimator.Estimate(); got != 0 {
		t.Fatalf("empty estimate = %d, want 0", got)
	}

	estimator.Observe("n1")
	estimator.Observe("n1")
	if got := estimator.Estimate(); got != 1 {
		t.Fatalf("repeated node estimate = %d, want 1", got)
	}

	estimator.ObserveNodes("n2", "n3", "n2", "")
	if got := estimator.Estimate(); got != 3 {
		t.Fatalf("distinct node estimate = %d, want 3", got)
	}

	if estimator.Forget("missing") {
		t.Fatal("forget should report false for a missing node")
	}
	if !estimator.Forget("n2") {
		t.Fatal("forget should report true for an observed node")
	}
	if got := estimator.Estimate(); got != 2 {
		t.Fatalf("estimate after forget = %d, want 2", got)
	}

	estimator.Reset()
	if got := estimator.Estimate(); got != 0 {
		t.Fatalf("estimate after reset = %d, want 0", got)
	}
}

func TestClusterSizeEstimatorWindow(t *testing.T) {
	estimator := NewClusterSizeEstimator(time.Minute)
	now := time.Date(2026, 6, 18, 20, 0, 0, 0, time.UTC)

	estimator.ObserveAt("old", now.Add(-2*time.Minute))
	estimator.ObserveAt("current", now.Add(-30*time.Second))
	estimator.ObserveAt("boundary", now.Add(-time.Minute))

	if got := estimator.EstimateAt(now); got != 2 {
		t.Fatalf("windowed estimate = %d, want 2", got)
	}

	estimator.ObserveAt("old", now)
	if got := estimator.EstimateAt(now); got != 3 {
		t.Fatalf("refreshed estimate = %d, want 3", got)
	}
}

